// src/components/FormPaciente.js
import React, { useState, useEffect } from 'react';
import axios from 'axios';

function FormPaciente({ onNovoPaciente, pacienteEditando, onFimEdicao }) {
  const [numeroProntuario, setNumeroProntuario] = useState('');
  const [nome, setNome] = useState('');
  const [telefone, setTelefone] = useState('');
  const [mensagem, setMensagem] = useState('');

  const [formData, setFormData] = useState({
    numero_gaveta: '',
    rg: '',
    cpf: '',
    cep: '',
    data_nascimento: '',
    idade: '',
    endereco: '',
    numero: '',
    cidade: '',
    observacao: ''
  });

  // Carrega dados quando estiver editando
  useEffect(() => {
    if (pacienteEditando) {
      setNumeroProntuario(pacienteEditando.numero_prontuario || '');
      setNome(pacienteEditando.nome || '');
      setTelefone(formatarTelefone(pacienteEditando.telefone || ''));
      setFormData({
        numero_gaveta: pacienteEditando.numero_gaveta || '',
        rg: pacienteEditando.rg || '',
        cpf: pacienteEditando.cpf || '',
        cep: pacienteEditando.cep || '',
        data_nascimento: pacienteEditando.data_nascimento
          ? pacienteEditando.data_nascimento.slice(0, 10)
          : '',
        idade: pacienteEditando.idade || '',
        endereco: pacienteEditando.endereco || '',
        numero: pacienteEditando.numero || '',
        cidade: pacienteEditando.cidade || '',
        observacao: pacienteEditando.observacao || ''
      });
    } else {
      setNumeroProntuario('');
      setNome('');
      setTelefone('');
      setFormData({
        numero_gaveta: '',
        rg: '',
        cpf: '',
        cep: '',
        data_nascimento: '',
        idade: '',
        endereco: '',
        numero: '',
        cidade: '',
        observacao: ''
      });
    }
    setMensagem('');
  }, [pacienteEditando]);

  // formata telefone
  function formatarTelefone(campo) {
    const d = campo.replace(/\D/g, '');
    if (!d) return '';
    if (d.length <= 2) return d.replace(/^(\d{0,2})/, '($1');
    if (d.length <= 6) return d.replace(/^(\d{2})(\d{0,4})/, '($1) $2');
    return d.replace(/^(\d{2})(\d{5})(\d{0,4}).*/, '($1) $2-$3');
  }

  // calcula idade a partir da data
  function calcularIdade(dataStr) {
    const hoje = new Date();
    const nasc = new Date(dataStr);
    let idade = hoje.getFullYear() - nasc.getFullYear();
    if (
      hoje.getMonth() < nasc.getMonth() ||
      (hoje.getMonth() === nasc.getMonth() && hoje.getDate() < nasc.getDate())
    ) {
      idade--;
    }
    return idade;
  }

  // lookup CEP ao perder foco
  async function handleCepBlur() {
    const cepLimpo = formData.cep.replace(/\D/g, '');
    if (cepLimpo.length !== 8) return;
    try {
      const resp = await axios.get(`https://viacep.com.br/ws/${cepLimpo}/json/`);
      if (!resp.data.erro) {
        setFormData(fd => ({
          ...fd,
          endereco: resp.data.logradouro || '',
          cidade: resp.data.localidade || ''
        }));
      }
    } catch {
      // falha no CEP, ignora
    }
  }

  // handlers gerais
  const handleNomeChange = e => setNome(e.target.value);
  const handleTelefoneChange = e => setTelefone(formatarTelefone(e.target.value));
  const handleNumeroProntuarioChange = e => setNumeroProntuario(e.target.value);

  const handleChange = e => {
    const { name, value } = e.target;
    setFormData(fd => ({ ...fd, [name]: value }));
  };

  // data_nascimento específica para calcular idade
  const handleDateChange = e => {
    const val = e.target.value;
    setFormData(fd => ({
      ...fd,
      data_nascimento: val,
      idade: val ? calcularIdade(val) : ''
    }));
  };

  const handleSubmit = async e => {
    e.preventDefault();
    setMensagem('');
    if (!nome.trim()) {
      setMensagem('O nome é obrigatório.');
      return;
    }
    const digitosTel = telefone.replace(/\D/g, '');
    if (!(digitosTel.length === 10 || digitosTel.length === 11)) {
      setMensagem('Telefone inválido. Use 10 ou 11 dígitos.');
      return;
    }
    // montar payload
    const payload = {
      numero_prontuario: numeroProntuario.trim() || null,
      nome: nome.trim(),
      telefone: digitosTel,
      ...formData
    };
    try {
      if (pacienteEditando) {
        await axios.put(`/api/pacientes/${pacienteEditando.id}`, payload);
        setMensagem('Paciente atualizado com sucesso!');
        onNovoPaciente();
      } else {
        await axios.post('/api/pacientes', payload);
        setMensagem('Paciente cadastrado com sucesso!');
        onNovoPaciente();
        // limpa
        setNome(''); setTelefone(''); setNumeroProntuario('');
        setFormData({
          numero_gaveta: '',
          rg: '',
          cpf: '',
          cep: '',
          data_nascimento: '',
          idade: '',
          endereco: '',
          numero: '',
          cidade: '',
          observacao: ''
        });
      }
    } catch {
      setMensagem(pacienteEditando
        ? 'Erro ao atualizar paciente.'
        : 'Erro ao cadastrar paciente.'
      );
    }
  };

  return (
    <div className="bg-white mx-auto max-w-auto rounded-2xl p-6">
      <form onSubmit={handleSubmit} autoComplete="off">
        <h2 className="text-2xl font-bold mb-6 text-gray-800">
          {pacienteEditando ? 'Editar Paciente' : 'Novo Paciente'}
        </h2>

        {/* Número do Prontuário e Nº Gaveta */}
        <div className="grid grid-cols-2 gap-4 mb-6">
          <div>
            <label className="block mb-2 font-medium text-gray-700">
              Número do Prontuário <small>(opcional)</small>
            </label>
            <input
              type="text" maxLength={8}
              value={numeroProntuario}
              onChange={handleNumeroProntuarioChange}
              className="w-full border rounded px-3 py-2"
            />
          </div>
          <div>
            <label className="block mb-2 font-medium text-gray-700">
              Nº Gaveta <small>(opcional)</small>
            </label>
            <input
              type="text"
              name="numero_gaveta"
              value={formData.numero_gaveta}
              onChange={handleChange}
              className="w-full border rounded px-3 py-2"
            />
          </div>
        </div>

        {/* Nome e Sobrenome */}
        <div className="mb-6">
          <label className="block mb-2 font-medium text-gray-700">
            Nome e Sobrenome
            <input
              type="text" required
              value={nome}
              onChange={handleNomeChange}
              placeholder="Nome completo"
              className="w-full border rounded px-3 py-2 mt-1"
            />
          </label>
        </div>

        {/* Telefone */}
        <div className="mb-6">
          <label className="block mb-2 font-medium text-gray-700">
            Telefone
            <input
              type="tel" required
              value={telefone}
              onChange={handleTelefoneChange}
              placeholder="(XX) XXXXX-XXXX"
              className="w-full border rounded px-3 py-2 mt-1"
            />
          </label>
        </div>

        {/* RG e CPF */}
        <div className="grid grid-cols-2 gap-4 mb-6">
          <div>
            <label className="block mb-2 font-medium text-gray-700">
              RG <small>(opcional)</small>
            </label>
            <input
              type="text"
              name="rg"
              value={formData.rg}
              onChange={handleChange}
              className="w-full border rounded px-3 py-2"
            />
          </div>
          <div>
            <label className="block mb-2 font-medium text-gray-700">
              CPF <small>(opcional)</small>
            </label>
            <input
              type="text"
              name="cpf"
              value={formData.cpf}
              onChange={handleChange}
              placeholder="000.000.000-00"
              className="w-full border rounded px-3 py-2"
            />
          </div>
        </div>



        {/* Data de Nascimento e Idade */}
        <div className="grid grid-cols-2 gap-4 mb-6">
          <div>
            <label className="block mb-2 font-medium text-gray-700">
              Data de Nascimento <small>(opcional)</small>
            </label>
            <input
              type="date"
              name="data_nascimento"
              value={formData.data_nascimento}
              onChange={handleDateChange}
              className="w-full border rounded px-3 py-2"
            />
          </div>
          <div>
            <label className="block mb-2 font-medium text-gray-700">
              Idade
            </label>
            <input
              type="number" readOnly
              name="idade"
              value={formData.idade}
              className="w-full border rounded px-3 py-2 bg-gray-100"
            />
          </div>
        </div>
        {/* CEP */}
        <div className="mb-6">
          <label className="block mb-2 font-medium text-gray-700">
            CEP <small>(opcional)</small>
          </label>
          <input
            type="text"
            name="cep"
            value={formData.cep}
            onChange={handleChange}
            onBlur={handleCepBlur}
            placeholder="00000-000"
            className="w-full border rounded px-3 py-2"
          />
        </div>
        {/* Endereço, Número e Cidade */}
        <div className="mb-6">
          <label className="block mb-2 font-medium text-gray-700">
            Endereço <small>(opcional)</small>
          </label>
          <input
            type="text"
            name="endereco"
            value={formData.endereco}
            onChange={handleChange}
            className="w-full border rounded px-3 py-2"
          />
        </div>
        <div className="grid grid-cols-2 gap-4 mb-6">
          <div>
            <label className="block mb-2 font-medium text-gray-700">
              Número <small>(opcional)</small>
            </label>
            <input
              type="text"
              name="numero"
              value={formData.numero}
              onChange={handleChange}
              className="w-full border rounded px-3 py-2"
            />
          </div>
          <div>
            <label className="block mb-2 font-medium text-gray-700">
              Cidade <small>(opcional)</small>
            </label>
            <input
              type="text"
              name="cidade"
              value={formData.cidade}
              onChange={handleChange}
              className="w-full border rounded px-3 py-2"
            />
          </div>
        </div>

        {/* Observação */}
        <div className="mb-6">
          <label className="block mb-2 font-medium text-gray-700">
            Observações <small>(opcional)</small>
          </label>
          <textarea
            name="observacao"
            value={formData.observacao}
            onChange={handleChange}
            className="w-full border rounded px-3 py-2 h-24"
          />
        </div>

        {/* Botões */}
        <div className="flex flex-col md:flex-row gap-4">
          <button
            type="submit"
            className="bg-[#1A1C2C] hover:bg-[#3B4854] text-white font-bold py-2 px-6 rounded-full"
          >
            {pacienteEditando ? 'Atualizar' : 'Cadastrar'}
          </button>
          {pacienteEditando && (
            <button
              type="button"
              onClick={onFimEdicao}
              className="bg-[#DA3648] text-white hover:bg-[#BC3140] px-4 py-2 rounded-full"
            >
              Cancelar
            </button>
          )}
        </div>

        {/* Feedback */}
        {mensagem && (
          <p className="mt-4 text-red-600">
            {mensagem}
          </p>
        )}
      </form>
    </div>
  );
}

export default FormPaciente;
